import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"虚拟资产账户","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/virtual-asset.md","filePath":"zh-CN/account/virtual-asset.md"}'),p={name:"account/virtual-asset.md"};function l(i,a,n,h,s,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="虚拟资产账户" tabindex="-1">虚拟资产账户 <a class="header-anchor" href="#虚拟资产账户" aria-label="Permalink to &quot;虚拟资产账户&quot;">​</a></h1><p>虚拟资产账户开户资格、支持币种、交易规则、手续费及注意事项。</p><h2 id="账户基本信息" tabindex="-1">账户基本信息 <a class="header-anchor" href="#账户基本信息" aria-label="Permalink to &quot;账户基本信息&quot;">​</a></h2><p>长桥虚拟资产账户（Crypto Account）是长桥香港提供的加密货币交易账户，账户号码以 H 开头，附带 Crypto Account 标识。</p><p>开户时效：1-2 个工作日。</p><h2 id="开户资格" tabindex="-1">开户资格 <a class="header-anchor" href="#开户资格" aria-label="Permalink to &quot;开户资格&quot;">​</a></h2><p>仅支持海外身份用户及香港永居身份用户开户。</p><h2 id="开户操作" tabindex="-1">开户操作 <a class="header-anchor" href="#开户操作" aria-label="Permalink to &quot;开户操作&quot;">​</a></h2><p>进入长桥 App - 市场，切换顶部标签至虚拟资产频道，点击感兴趣的加密货币进入详情页，点击买入或卖出按钮即可根据指引提交开户申请。</p><p>账户成功开通后，可通过入金或账户内划转资金的方式为虚拟资产账户存入资金。</p><p>目前虚拟货币账户仅支持现金账户，不支持融资功能。</p><h2 id="支持品类" tabindex="-1">支持品类 <a class="header-anchor" href="#支持品类" aria-label="Permalink to &quot;支持品类&quot;">​</a></h2><p>长桥目前支持包括 BTC、ETH、LTC、DOGE 等主流加密货币在内的十多种加密货币交易，并持续扩展交易范围。</p><p>支持的订单类型：限价单、市价单。</p><p>订单有效期：撤单前有效（GTC）。</p><p>交易时段：7×24 小时全天候交易，无休市日。</p><p>限制：暂不支持融资交易与做空操作，交易需 100% 保证金。暂不支持加密货币的直接存入或提取，功能开发中。</p><p>注意：非专业投资者仅可交易 BTC/USD、BTC/HKD、ETH/USD、ETH/HKD、AVAX/USD、LINK/USD 和 SOL/USD。其他币种仅限专业投资者交易。可交易币种会持续变动，最新可交易币种请以交易系统显示为准。</p><h2 id="交易收费" tabindex="-1">交易收费 <a class="header-anchor" href="#交易收费" aria-label="Permalink to &quot;交易收费&quot;">​</a></h2><blockquote><p>佣金：优惠推广期间，所有加密货币交易均为 0 佣金，直至另行通知。</p><p>平台费：0.08% × 交易金额，每笔订单最低 1.99 美元或 15 港元。</p><p>月度管理费：（持仓市值 × 0.003）÷ 365，按月收取。</p></blockquote><h2 id="风险测评" tabindex="-1">风险测评 <a class="header-anchor" href="#风险测评" aria-label="Permalink to &quot;风险测评&quot;">​</a></h2><p>开户或交易前需完成风险测评，风险测评默认有效期 1 年。若未提交过或即将过期，APP 会弹出填写界面，按照页面提示根据自己实际情况填写即可。</p><h2 id="注销账户" tabindex="-1">注销账户 <a class="header-anchor" href="#注销账户" aria-label="Permalink to &quot;注销账户&quot;">​</a></h2><p>如需注销虚拟资产账户，请填写注销申请表并发送邮件至香港官方邮箱。</p><p><a href="https://pub.lbkrs.com/files/202602/LS5FyJKJf5ZmQAVT/___20260225.pdf" target="_blank" rel="noreferrer">注销申请表</a><br> 提交邮箱：service@longbridge.hk</p><p>如仅注销虚拟资产账户（保留证券账户），请在申请表中勾选&quot;取消证券交易账户&quot;，并备注虚拟资产账户的证券号码。</p>',26)])])}const _=e(p,[["render",l]]);export{u as __pageData,_ as default};
